+    fn test_spec_ansi_codes_bright_all() {
+        for n in 8..16u8 {
+            let c = Color::from_ansi(n);
+            // Spec says 82+n for fg, 92+n for bg
+            assert_eq!(c.get_ansi_codes(true), vec![(82 + n).to_string()]);
+            assert_eq!(c.get_ansi_codes(false), vec![(92 + n).to_string()]);
