+    // 1.5 ANSI Codes - EIGHT_BIT background
+    #[test]
+    fn test_spec_ansi_codes_eight_bit_bg() {
+        let c = Color::from_ansi(196);
+        assert_eq!(c.get_ansi_codes(false), vec!["48", "5", "196"]);
+    }
